(function () {
  function addStyle() { if (document.getElementById('mc-style')) return; var s = document.createElement('style'); s.id = 'mc-style'; s.textContent = '.mc-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.mc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(130px,1fr));gap:12px}.mc-grid label{display:flex;flex-direction:column;gap:5px}.mc-grid input{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.mc-actions{display:flex;gap:8px;flex-wrap:wrap;margin:12px 0}.mc-out{padding:12px;border-radius:8px;background:#f8f9fa;line-height:1.7}.mc-result{margin-top:8px;padding:10px;border-radius:8px;background:#d4edda;border-left:4px solid #28a745}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.mcMounted) return; host.dataset.mcMounted = '1'; addStyle(); host.innerHTML = '<div class="mc-wrap"><h4>🔢 Máy tính số học modulo</h4><div class="mc-grid"><label>a <input data-a type="number" value="17"></label><label>b <input data-b type="number" value="3"></label><label>m <input data-m type="number" min="1" value="13"></label></div><div class="mc-actions"><button type="button" data-op="add">+ mod m</button><button type="button" data-op="sub">- mod m</button><button type="button" data-op="mul">× mod m</button><button type="button" data-op="pow">a^b mod m</button></div><div class="mc-out"></div></div>'; var out = host.querySelector('.mc-out'); function mod(x, m) { return ((x % m) + m) % m; } function val(s) { return parseInt(host.querySelector(s).value, 10) || 0; } function pow(a, b, m) { var res = 1, base = mod(a, m), steps = []; while (b > 0) { steps.push('b=' + b + ', res=' + res + ', base=' + base); if (b % 2) res = mod(res * base, m); base = mod(base * base, m); b = Math.floor(b / 2); } return { res: res, steps: steps }; } function run(op) { var a = val('[data-a]'), b = val('[data-b]'), m = Math.max(1, val('[data-m]')), r, text; if (op === 'add') { r = mod(a + b, m); text = '(' + a + ' + ' + b + ') mod ' + m + ' = ' + (a + b) + ' mod ' + m; } if (op === 'sub') { r = mod(a - b, m); text = '(' + a + ' - ' + b + ') mod ' + m + ' = ' + (a - b) + ' mod ' + m; } if (op === 'mul') { r = mod(a * b, m); text = '(' + a + ' × ' + b + ') mod ' + m + ' = ' + (a * b) + ' mod ' + m; } if (op === 'pow') { var p = pow(a, Math.max(0, b), m); r = p.res; text = a + '^' + b + ' mod ' + m + '<br>' + p.steps.join('<br>'); } out.innerHTML = text + '<div class="mc-result">Kết quả: <strong>' + r + '</strong></div>'; } host.querySelectorAll('[data-op]').forEach(function (b) { b.addEventListener('click', function () { run(b.dataset.op); }); }); run('pow'); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="modular-calculator"]').forEach(mount); });
}());
